// NuGet: Asp.Versioning.Http (Minimal API) hoặc Asp.Versioning.Mvc (Controllers)
builder.Services.AddApiVersioning(opt =>
{
    opt.DefaultApiVersion = new ApiVersion(1);
    opt.AssumeDefaultVersionWhenUnspecified = true;
    opt.ReportApiVersions = true; // thêm api-supported-versions header
    opt.ApiVersionReader = ApiVersionReader.Combine(
        new UrlSegmentApiVersionReader(),    // /api/v1/
        new HeaderApiVersionReader("api-version"), // header
        new QueryStringApiVersionReader("api-version")); // ?api-version=1.0
});

// Minimal API
var apiV1 = app.NewApiVersionSet()
    .HasApiVersion(new ApiVersion(1))
    .HasDeprecatedApiVersion(new ApiVersion(0, 9))
    .Build();

var v1 = app.MapGroup("/api/v{version:apiVersion}/orders")
    .WithApiVersionSet(apiV1);

v1.MapGet("", async (ApiVersion version, OrderService svc, CancellationToken ct) =>
    await svc.GetAllAsync(ct))
   .MapToApiVersion(1);

// Swagger per version
builder.Services.AddEndpointsApiExplorer();
builder.Services.AddSwaggerGen(opt =>
{
    opt.SwaggerDoc("v1", new() { Title = "Order API", Version = "v1" });
    opt.SwaggerDoc("v2", new() { Title = "Order API", Version = "v2" });
});
